use std::str::from_utf8;
use std::sync::Arc;

use anyhow::{Context, Result, bail};
use async_trait::async_trait;
use lettre::message::Mailbox;
use lettre::message::MessageBuilder;
use lettre::transport::smtp::authentication::Credentials;
use lettre::{AsyncSmtpTransport, AsyncTransport, Message, Tokio1Executor};
#[cfg(test)]
use mockall::automock;

use crate::{
    logic::secrets::{SecretKey, SecretProvider},
    models::{EmailAccount, EmailType},
};

/// How to look up an [`EmailAccount`] on the [`EmailGateway`].
///
/// Unifies the two pre-existing lookup modes (`get_account_by_type` and
/// `get_account_by_address`) behind a single gateway method so the trait stays
/// shallow while still supporting events that override their sender via
/// `alt_email_address`.
#[derive(Clone, Debug, PartialEq, Eq)]
pub(crate) enum AccountLookup {
    ByType(EmailType),
    ByAddress(String),
}

impl From<EmailType> for AccountLookup {
    fn from(email_type: EmailType) -> Self {
        Self::ByType(email_type)
    }
}

fn mailbox(account: &EmailAccount) -> Result<Mailbox> {
    Ok(account.address.parse()?)
}

fn create_mailer(account: &EmailAccount) -> Result<AsyncSmtpTransport<Tokio1Executor>> {
    let transport = AsyncSmtpTransport::<Tokio1Executor>::relay("smtp.gmail.com")?
        .credentials(Credentials::new(
            account.address.clone(),
            from_utf8(&account.password)
                .with_context(|| {
                    format!("Invalid UTF-8 sequence in password of {}", account.address)
                })?
                .into(),
        ))
        .build();
    Ok(transport)
}

async fn send_messages(from: &EmailAccount, messages: Vec<Message>) -> Result<()> {
    let mailer = create_mailer(from)?;
    for message in messages {
        mailer.send(message).await?;
    }
    Ok(())
}

/// Deep email seam: every outbound email in the codebase goes through this
/// trait. It owns the three operations a caller needs — sending a batch of
/// pre-built messages, building a message rooted at a sender account, and
/// resolving the sender account itself — so that `new_message_builder` and
/// `mailbox` can stay private to this module.
#[async_trait]
#[cfg_attr(test, automock)]
pub trait EmailGateway {
    /// Send `messages` from `from`, batching over a single SMTP connection.
    async fn send_messages(
        &self,
        from: &EmailAccount,
        messages: Vec<Message>,
    ) -> Result<()>;

    /// Start building a [`Message`] rooted at `account` (sets `from` and the
    /// current date). Callers chain `.to()`, `.subject()`, `.singlepart()`,
    /// etc. and finalize with `?` on the resulting `Message`.
    fn build_message(&self, account: &EmailAccount) -> Result<MessageBuilder>;

    /// Resolve the [`EmailAccount`] for a given lookup (by type or by
    /// explicit address, e.g. an event's `alt_email_address`).
    async fn account(&self, lookup: AccountLookup) -> Result<EmailAccount>;
}

#[derive(Clone)]
pub(crate) struct RealEmailGateway {
    secrets: Arc<dyn SecretProvider>,
}

impl RealEmailGateway {
    pub(crate) fn new(secrets: Arc<dyn SecretProvider>) -> Self {
        Self { secrets }
    }

    async fn email_accounts(&self) -> Result<Vec<EmailAccount>> {
        let email_accounts: Vec<EmailAccount> =
            serde_json::from_str(&self.secrets.get(SecretKey::EmailAccounts).await?)?;
        Ok(email_accounts)
    }

    /// Test the SMTP connectivity of every configured account. Health-check
    /// only — not part of [`EmailGateway`] because it has no business logic
    /// and never needs mocking beyond the connectivity task wrapper.
    pub(crate) async fn test_connection(&self) -> Result<()> {
        let mut errors = Vec::new();
        for email_account in self.email_accounts().await? {
            let result = create_mailer(&email_account)?.test_connection().await;
            match result {
                Ok(result) => {
                    if !result {
                        errors.push(format!(
                            "Testing connection of {} failed: {}",
                            email_account.address, "test_connection returned false"
                        ))
                    }
                }
                Err(e) => errors.push(format!(
                    "Testing connection of {} failed: {}",
                    email_account.address, e
                )),
            }
        }

        if !errors.is_empty() {
            bail!(
                "{} errors while testing connections:\n\n{}",
                errors.len(),
                errors.join("\n")
            );
        }

        Ok(())
    }
}

#[async_trait]
impl EmailGateway for RealEmailGateway {
    async fn send_messages(
        &self,
        from: &EmailAccount,
        messages: Vec<Message>,
    ) -> Result<()> {
        send_messages(from, messages).await
    }

    fn build_message(&self, account: &EmailAccount) -> Result<MessageBuilder> {
        Ok(Message::builder().from(mailbox(account)?).date_now())
    }

    async fn account(&self, lookup: AccountLookup) -> Result<EmailAccount> {
        let accounts = self.email_accounts().await?;
        match lookup {
            AccountLookup::ByType(email_type) => accounts
                .into_iter()
                .find(|account| account.email_type == email_type)
                .with_context(|| format!("Found no email account for email type {:?}", email_type)),
            AccountLookup::ByAddress(email_address) => accounts
                .into_iter()
                .find(|account| account.address == email_address)
                .with_context(|| {
                    format!(
                        "Found no email account for email address '{}'",
                        email_address
                    )
                }),
        }
    }
}

