use std::sync::{Arc, Mutex};

use lettre::Message;

use crate::email::{AccountLookup, MockEmailGateway};
use crate::models::{EmailAccount, EmailType};

/// Canonical mock [`EmailGateway`]. Configures every lookup mode and a
/// capturing `send_messages` so each test gets:
///   - account resolution (by type *and* by address, matching the `accounts`
///     list, with the rest returning the configured address)
///   - a real `MessageBuilder` from `build_message` so messages build offline
///   - `send_messages` captures `(account, Vec<Message>)` per call
///
/// Tests that don't care about captured messages simply ignore the returned
/// buffer. No-op cases (no expectations needed) use `MockEmailGateway::new()`
/// directly — the default mock panics on any call, which is the desired
/// "this path must not touch email" signal.
pub(crate) fn mock_email_gateway(
    accounts: Vec<(EmailType, &str)>,
) -> (MockEmailGateway, Arc<Mutex<Vec<(EmailAccount, Vec<Message>)>>>) {
    let mut mock = MockEmailGateway::new();

    for (email_type, address) in &accounts {
        let account = EmailAccount::new_for_test(email_type.clone(), address);
        let by_type = email_type.clone();
        mock.expect_account()
            .withf(move |lookup| matches!(lookup, AccountLookup::ByType(t) if t == &by_type))
            .returning(move |_| {
                let account = account.clone();
                Box::pin(async move { Ok(account) })
            });

        let account = EmailAccount::new_for_test(email_type.clone(), address);
        let by_address = address.to_string();
        mock.expect_account()
            .withf(move |lookup| {
                matches!(lookup, AccountLookup::ByAddress(a) if a == &by_address)
            })
            .returning(move |_| {
                let account = account.clone();
                Box::pin(async move { Ok(account) })
            });
    }

    mock.expect_build_message()
        .returning(|account| Ok(lettre::Message::builder().from(account.mailbox()?).date_now()));

    let captured: Arc<Mutex<Vec<(EmailAccount, Vec<Message>)>>> = Arc::new(Mutex::new(Vec::new()));
    let for_send = captured.clone();
    mock.expect_send_messages().returning(move |account, messages| {
        for_send.lock().unwrap().push((account.clone(), messages));
        Box::pin(async { Ok(()) })
    });

    (mock, captured)
}

use crate::email::{AccountLookup, EmailGateway};
use crate::models::{ContactMessage, Email, EmailType};
use anyhow::Result;
use lettre::message::SinglePart;
use std::collections::HashMap;
use tracing::info;

/// Build the plain text body for a contact message
fn build_contact_body(contact_message: &ContactMessage) -> String {
    let email = contact_message.email.trim();
    let mut body = format!(
        "Vor- und Nachname: {}\nEmail: {}\n",
        contact_message.name.trim(),
        email
    );
    if let Some(phone) = &contact_message.phone {
        let phone = phone.trim();
        if !phone.is_empty() {
            body.push_str(&format!("Telefon: {}\n", phone));
        }
    }
    body.push_str(&format!(
        "\nNachricht: {}\n",
        contact_message.message.trim()
    ));
    body
}

pub(crate) async fn message(
    contact_message: ContactMessage,
    email_sender: &impl EmailGateway,
) -> Result<()> {
    let email_account = email_sender
        .account(AccountLookup::ByType(contact_message.message_type.into()))
        .await?;

    let body = build_contact_body(&contact_message);

    let message = email_sender
        .build_message(&email_account)?
        .subject(format!(
            "[Kontakt@Web] Nachricht von {}",
            contact_message.name
        ))
        .to(contact_message.to.parse()?)
        .reply_to(contact_message.email.parse()?)
        .singlepart(SinglePart::plain(body))?;

    email_sender
        .send_messages(&email_account, vec![message])
        .await?;

    info!("Info message has been send successfully");

    Ok(())
}

pub(crate) async fn emails(emails: Vec<Email>, email_sender: &impl EmailGateway) -> Result<()> {
    let mut grouped_emails: HashMap<EmailType, Vec<Email>> = HashMap::new();
    for email in emails {
        let email_type = email.message_type.into();
        grouped_emails.entry(email_type).or_default().push(email);
    }
    for (email_type, emails) in grouped_emails {
        let from = email_sender
            .account(AccountLookup::ByType(email_type))
            .await?;
        let messages = emails
            .into_iter()
            .map(|email| email.into_message(&from, email_sender))
            .collect::<anyhow::Result<Vec<_>>>()?;
        email_sender.send_messages(&from, messages).await?;
    }

    Ok(())
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::models::EmailType;
    use crate::test_utils::mock_email_gateway;
    use pretty_assertions::assert_eq;

    #[tokio::test]
    async fn test_message_sends_to_correct_account() {
        let (mock_sender, captured) =
            mock_email_gateway(vec![(EmailType::Info, "info@sv-eutingen.de")]);

        let contact_message = ContactMessage {
            name: "Max Mustermann".to_string(),
            email: "max@example.com".to_string(),
            phone: Some("12345".to_string()),
            message: "Test message".to_string(),
            message_type: crate::models::MessageType::General,
            to: "info@sv-eutingen.de".to_string(),
            token: None,
        };

        let result = message(contact_message, &mock_sender).await;
        assert!(result.is_ok());

        let batches = captured.lock().unwrap();
        let total_messages: usize = batches.iter().map(|(_, msgs)| msgs.len()).sum();
        assert_eq!(total_messages, 1, "One email should have been sent");
    }

    #[tokio::test]
    async fn test_emails_groups_by_type_and_sends() {
        let emails_vec = vec![
            Email::new(
                crate::models::MessageType::General,
                "recipient1@example.com".to_string(),
                "Test 1".to_string(),
                "Body 1".to_string(),
                None,
            ),
            Email::new(
                crate::models::MessageType::General,
                "recipient2@example.com".to_string(),
                "Test 2".to_string(),
                "Body 2".to_string(),
                None,
            ),
            Email::new(
                crate::models::MessageType::Events,
                "recipient3@example.com".to_string(),
                "Event".to_string(),
                "Event body".to_string(),
                None,
            ),
        ];

        let (mock_sender, captured) = mock_email_gateway(vec![
            (EmailType::Info, "info@sv-eutingen.de"),
            (EmailType::Events, "events@sv-eutingen.de"),
        ]);

        let result = emails(emails_vec, &mock_sender).await;
        assert!(result.is_ok());

        let batches = captured.lock().unwrap();
        assert_eq!(batches.len(), 2);

        let info_batch = batches
            .iter()
            .find(|(a, _)| a.address == "info@sv-eutingen.de")
            .unwrap();
        assert_eq!(info_batch.1.len(), 2);

        let events_batch = batches
            .iter()
            .find(|(a, _)| a.address == "events@sv-eutingen.de")
            .unwrap();
        assert_eq!(events_batch.1.len(), 1);
    }
}

