use crate::logic::secrets::MockSecretProvider;
    use crate::models::{EventBooking, EventType, LifecycleStatus, PartialEvent, PaymentMethod};
    use crate::test_utils::mock_email_gateway;

    use super::*;

    fn mock_gateway_discarding(
        accounts: Vec<(crate::models::EmailType, &str)>,
    ) -> crate::email::MockEmailGateway {
        mock_email_gateway(accounts).0
    }

    fn mock_gateway_capturing(
        accounts: Vec<(crate::models::EmailType, &str)>,
    ) -> (
        crate::email::MockEmailGateway,
        std::sync::Arc<std::sync::Mutex<Vec<lettre::Message>>>,
    ) {
        use std::sync::{Arc, Mutex};

        let (mock, batches) = mock_email_gateway(accounts);
        let messages = Arc::new(Mutex::new(Vec::new()));
        let for_msg = messages.clone();
        mock.expect_send_messages()
            .returning(move |_, msgs| {
                for_msg
                    .lock()
                    .unwrap()
                    .extend(msgs.into_iter().cloned());
                Box::pin(async { Ok(()) })
            });
        (mock, batches_buffer_to_messages(messages, batches))
    }

    fn batches_buffer_to_messages(
        messages: std::sync::Arc<std::sync::Mutex<Vec<lettre::Message>>>,
        _batches: std::sync::Arc<std::sync::Mutex<Vec<(crate::models::EmailAccount, Vec<lettre::Message>)>>>,
    ) -> std::sync::Arc<std::sync::Mutex<Vec<lettre::Message>>> {
        messages
    }

