use crate::logic::secrets::MockSecretProvider;
    use crate::models::{EventBooking, EventType, LifecycleStatus, PartialEvent, PaymentMethod};
    use crate::test_utils::mock_email_gateway;

    use super::*;

    /// Mock gateway where account-by-type lookup is expected exactly `times`
    /// and sends are discarded. Used by tests that assert an email fires a
    /// bounded number of times without inspecting content.
    fn mock_gateway_discarding(
        accounts: Vec<(crate::models::EmailType, &str)>,
    ) -> crate::email::MockEmailGateway {
        mock_email_gateway(accounts).0
    }

    fn mock_gateway_times(
        accounts: Vec<(crate::models::EmailType, &str)>,
        times: usize,
    ) -> crate::email::MockEmailGateway {
        use crate::email::{AccountLookup, MockEmailGateway};
        use crate::models::EmailAccount;
        let mut mock = MockEmailGateway::new();
        for (email_type, address) in accounts {
            let account = EmailAccount::new_for_test(email_type.clone(), address);
            let by_type = email_type.clone();
            mock.expect_account()
                .withf(move |lookup| matches!(lookup, AccountLookup::ByType(t) if t == &by_type))
                .times(times)
                .returning(move |_| {
                    let account = account.clone();
                    Box::pin(async move { Ok(account) })
                });
        }
        mock.expect_build_message()
            .returning(|account| Ok(lettre::Message::builder().from(account.mailbox()?).date_now()));
        mock.expect_send_messages()
            .returning(|_, _| Box::pin(async { Ok(()) }));
        mock
    }

